import{_ as t,v as a,f as o,i as r}from"./chunks/framework.jfF5glnW.js";const m=JSON.parse('{"title":"Week 1 | Git 与 HTML 入门","description":"","frontmatter":{"title":"Week 1 | Git 与 HTML 入门","date":"2026-03-03T00:00:00.000Z","tags":["课程周志","Git","HTML"],"cover":"/code2real_blog/posts/week1/speede.jpg"},"headers":[],"relativePath":"posts/week1.md","filePath":"posts/week1.md"}'),i={name:"posts/week1.md"};function c(d,e,s,l,n,h){return a(),o("div",null,[...e[0]||(e[0]=[r('<p>第一周的重点并不在于完成某个具体作品，而在于建立后续课程开展所需的基础环境。本周主要学习 Git 的基本使用方式，并开始使用 HTML 搭建课程网站。</p><hr><img src="/code2real_blog/posts/week1/speede.jpg" alt="Week 1 image"><h2 id="本周学习内容" tabindex="-1">本周学习内容 <a class="header-anchor" href="#本周学习内容" aria-label="Permalink to &quot;本周学习内容&quot;">​</a></h2><p>本周聚焦两项基础工具：Git 与 HTML。Git 部分涉及仓库初始化、文件追踪、提交记录管理以及与远程仓库交互的基本概念；HTML 部分围绕网页标准结构、常用标签展开，并开始搭建个人课程网站的初始页面。这周工作主要为后续周志、文件归档和阶段成果整理建立统一框架。</p><h2 id="实践过程" tabindex="-1">实践过程 <a class="header-anchor" href="#实践过程" aria-label="Permalink to &quot;实践过程&quot;">​</a></h2><p>Git 实践中，我梳理了工作区、暂存区、本地仓库和远程仓库之间的协作关系。通过依次执行 <code>git init</code>、<code>git add</code>、<code>git commit</code> 等操作，明确“修改文件—加入暂存区—生成提交记录”的边界，体会到版本控制在课程项目中的工程价值。<br> HTML 方面，从标准文档骨架（<code>&lt;!DOCTYPE html&gt;</code>、<code>&lt;html&gt;</code>、<code>&lt;head&gt;</code>、<code>&lt;body&gt;</code>）开始，练习标题、段落、图片、超链接等元素，搭建了页面间跳转关系，初步理解内容组织与文件路径依赖。</p><h2 id="遇到的问题" tabindex="-1">遇到的问题 <a class="header-anchor" href="#遇到的问题" aria-label="Permalink to &quot;遇到的问题&quot;">​</a></h2><p>混淆主要出现在 Git 工作流中：起初容易把工作区改动与已提交状态等同，对 <code>git add</code> 和 <code>git commit</code> 的职责划分不够清晰。经过反复操作，才确切区分“修改”“暂存”“记录”三阶段。<br> HTML 的困难集中于相对路径配置：页面可正常显示，但图片或链接因路径层级错误而加载失败。定位后发现需仔细核对 <code>src</code>、<code>href</code> 中的目录引用，确保相对路径正确。</p><h2 id="本周收获" tabindex="-1">本周收获 <a class="header-anchor" href="#本周收获" aria-label="Permalink to &quot;本周收获&quot;">​</a></h2><p>掌握了课程网站的基本构成与 Git 的记录机制，为后续内容更新和历史追溯提供支撑。第一周虽然偏基础，但确立了记录规范与文件组织方式，使后续产出可被持续、清晰地保存，对整个课程具有明显的奠基作用。</p><hr><h2 id="友情链接" tabindex="-1">友情链接 <a class="header-anchor" href="#友情链接" aria-label="Permalink to &quot;友情链接&quot;">​</a></h2><p><a href="https://git-scm.com/book/en/v2" target="_blank" rel="noreferrer">https://git-scm.com/book/en/v2</a></p><p><a href="https://missing.csail.mit.edu/2020/version-control/" target="_blank" rel="noreferrer">https://missing.csail.mit.edu/2020/version-control/</a></p><p><a href="https://github.com/sinokkkk/code2real_blog" target="_blank" rel="noreferrer">https://github.com/sinokkkk/code2real_blog</a></p><img src="/code2real_blog/posts/week1/1.png" alt="Week 1 image">',17)])])}const g=t(i,[["render",c]]);export{m as __pageData,g as default};
